namespace WidgetFlags {
    constexpr uint16_t Visible            = 0x0001;
    constexpr uint16_t Enabled            = 0x0002;
    constexpr uint16_t Focusable          = 0x0004;
    constexpr uint16_t Focused            = 0x0008;
    constexpr uint16_t Hovered            = 0x0010;
    constexpr uint16_t Pressed            = 0x0020;
    constexpr uint16_t Dirty              = 0x0040;
    constexpr uint16_t LayoutDirty        = 0x0080;
    constexpr uint16_t ClipChildren       = 0x0100;
    constexpr uint16_t CapturesMouse      = 0x0200;
    constexpr uint16_t RendersOwnChildren = 0x0400;
    // Focus system flags
    constexpr uint16_t FocusGroup         = 0x0800;  // Container traps arrow navigation
    constexpr uint16_t FocusScope         = 0x1000;  // Isolates Tab navigation (dialogs)
    constexpr uint16_t PreferInitialFocus = 0x2000;  // Widget to focus when scope opens
    constexpr uint16_t SkipTabStop        = 0x4000;  // Arrows can reach but Tab skips
    constexpr uint16_t KeyboardFocused    = 0x8000;  // Show keyboard focus ring (Tab nav shows ring, mouse click doesn't)
}

// ============================================================================
// Size Mode
// ============================================================================

enum class SizeMode : uint8_t {
    Fixed,
    Fill,
    Hug,
    Percent
};

// Navigation direction for focus groups
enum class NavDirection : uint8_t {
    Auto = 0,        // Infer from FlexDirection (Row->Horizontal, Column->Vertical)
    Horizontal = 1,  // Left/Right arrows navigate siblings
    Vertical = 2,    // Up/Down arrows navigate siblings
    Grid = 3         // All arrows navigate spatially
};

// ============================================================================
// Layout Types
// ============================================================================

struct LayoutRect {
    float x = 0.0f;
    float y = 0.0f;
    float width = 0.0f;
    float height = 0.0f;

    bool contains(float px, float py) const {
        return px >= x && px < x + width && py >= y && py < y + height;
    }
};

struct LayoutConstraints {
    float min_width = 0.0f;
    float max_width = FLT_MAX;
    float min_height = 0.0f;
    float max_height = FLT_MAX;
};

// ============================================================================
// Easing Functions
// ============================================================================

namespace Easing {
    inline float linear(float t) { return t; }

    // Ease-out (decelerate) - primary for UI hover transitions
    inline float ease_out_quad(float t) {
        return 1.0f - (1.0f - t) * (1.0f - t);
    }

    // Ease-out cubic - smoother deceleration
    inline float ease_out_cubic(float t) {
        float f = 1.0f - t;
        return 1.0f - f * f * f;
    }

    // Ease-in-out - for symmetric animations
    inline float ease_in_out_quad(float t) {
        return t < 0.5f
            ? 2.0f * t * t
            : 1.0f - (-2.0f * t + 2.0f) * (-2.0f * t + 2.0f) / 2.0f;
    }
}

// ============================================================================
// Animation Structs
// ============================================================================

// Smooth hover transition state
struct HoverAnimation {
    float current = 0.0f;   // Current interpolated value (0.0 = not hovered, 1.0 = fully hovered)
    float target = 0.0f;    // Target value (0 or 1)
    bool is_animating = false;  // Track scheduler registration

    // Update animation toward target. Returns true if still animating.
    bool update(float dt, float duration_ms) {
        if (fabsf(target - current) < 0.001f) {
            current = target;
            if (is_animating) {
                is_animating = false;
                g_animation_scheduler.animation_ended();
            }
            return false;
        }

        // Animation is active
        if (!is_animating) {
            is_animating = true;
            g_animation_scheduler.animation_started();
        }

        float speed = 1000.0f / duration_ms;
        if (current < target) {
            current = fminf(current + speed * dt, target);
        } else {
            current = fmaxf(current - speed * dt, target);
        }
        return true;
    }

    // Called when widget is destroyed or animation is force-cancelled
    void cancel() {
        if (is_animating) {
            is_animating = false;
            g_animation_scheduler.animation_ended();
        }
    }

    // Get eased value for rendering
    float eased() const {
        return Easing::ease_out_quad(current);
    }
};

// Button press scale animation
struct PressAnimation {
    float scale = 1.0f;      // Current scale (1.0 = normal, 0.98 = pressed)
    float target = 1.0f;     // Target scale
    bool is_animating = false;  // Track scheduler registration

    // Update animation. Returns true if still animating.
    bool update(float dt) {
        float diff = target - scale;
        if (fabsf(diff) < 0.001f) {
            scale = target;
            if (is_animating) {
                is_animating = false;
                g_animation_scheduler.animation_ended();
            }
            return false;
        }

        if (!is_animating) {
            is_animating = true;
            g_animation_scheduler.animation_started();
        }

        // Fast spring-like response
        scale += diff * 20.0f * dt;
        return true;
    }

    // Called when widget is destroyed or animation is force-cancelled
    void cancel() {
        if (is_animating) {
            is_animating = false;
            g_animation_scheduler.animation_ended();
        }
    }
};

// Animation guard: tracks scheduler registration for animations that are
// driven directly inside tick() (cursor blink, progress marquee, etc.)
// rather than through HoverAnimation/PressAnimation. Without this, a
// custom animation that only calls set_dirty() will stop after one frame
// because the render loop has no reason to keep ticking.
//
// Use as a member of the widget. Call start() each tick the animation
// is active; call stop() when settled. Idempotent; cancel() in dtor.
struct AnimGuard {
    bool active = false;

    void start() {
        if (!active) {
            active = true;
            g_animation_scheduler.animation_started();
        }
    }

    void stop() {
        if (active) {
            active = false;
            g_animation_scheduler.animation_ended();
        }
    }

    // Alias matching HoverAnimation/PressAnimation
    void cancel() { stop(); }

    ~AnimGuard() { stop(); }
};

// Scroll helper for direct scroll position tracking
// Touchpad drivers handle inertia naturally by continuing to send scroll events after finger lift
// Mouse wheel sends discrete events - no momentum needed there either
struct ScrollMomentum {
    // Called on scroll wheel input - applies direct position change
    void on_scroll_input(float delta_pixels, float& scroll_pos, float max_scroll) {
        scroll_pos -= delta_pixels;
        if (scroll_pos < 0.0f) scroll_pos = 0.0f;
        else if (scroll_pos > max_scroll) scroll_pos = max_scroll;
    }

    // No animation needed - driver handles touchpad momentum
    bool update(float /*dt*/, float /*time*/, float& /*scroll_pos*/, float /*max_scroll*/) {
        return false;
    }
};

