// ============================================================================
// Widget Base Struct
// ============================================================================

struct Widget {
    WidgetId id;
    const char* debug_name = nullptr;

    Widget* parent = nullptr;
    Widget* first_child = nullptr;
    Widget* last_child = nullptr;
    Widget* next_sibling = nullptr;
    Widget* prev_sibling = nullptr;
    size_t child_count = 0;

    uint16_t flags = WidgetFlags::Visible | WidgetFlags::Enabled;

    LayoutRect rect = {};

    float preferred_width = 0.0f;
    float preferred_height = 0.0f;

    float padding_left = 0.0f;
    float padding_right = 0.0f;
    float padding_top = 0.0f;
    float padding_bottom = 0.0f;

    SizeMode width_mode = SizeMode::Hug;
    SizeMode height_mode = SizeMode::Hug;
    float flex = 0.0f;

    // Focus navigation fields
    int16_t tab_index = 0;                           // -1 = skip, 0 = tree order, 1+ = explicit order
    NavDirection nav_direction = NavDirection::Auto; // For FocusGroup containers

    // Animation state (lazily allocated)
    HoverAnimation* hover_anim = nullptr;
    PressAnimation* press_anim = nullptr;

    Widget() : id(g_next_widget_id++) {}
    virtual ~Widget() {
        // Clean up animation scheduler registrations
        if (hover_anim) {
            hover_anim->cancel();
        }
        if (press_anim) {
            press_anim->cancel();
        }
    }

    virtual void measure(const LayoutConstraints& constraints) {
        rect.width = fminf(fmaxf(preferred_width, constraints.min_width), constraints.max_width);
        rect.height = fminf(fmaxf(preferred_height, constraints.min_height), constraints.max_height);
    }

    virtual void layout() {}

    virtual void render(RenderContext& ctx) { (void)ctx; }

    virtual bool on_mouse_enter() { return false; }
    virtual bool on_mouse_leave() { return false; }
    virtual bool on_mouse_move(float x, float y) { (void)x; (void)y; return false; }
    virtual bool on_mouse_down(float x, float y, int button) { (void)x; (void)y; (void)button; return false; }
    virtual bool on_mouse_up(float x, float y, int button) { (void)x; (void)y; (void)button; return false; }
    virtual bool on_mouse_wheel(float x, float y, float delta) { (void)x; (void)y; (void)delta; return false; }
    virtual bool on_mouse_hwheel(float x, float y, float delta) { (void)x; (void)y; (void)delta; return false; }  // Horizontal wheel
    virtual bool on_double_click(float x, float y, int button) { (void)x; (void)y; (void)button; return false; }

    virtual bool on_key_down(int vk, bool ctrl, bool shift, bool alt) { (void)vk; (void)ctrl; (void)shift; (void)alt; return false; }
    virtual bool on_key_up(int vk) { (void)vk; return false; }
    virtual bool on_char(wchar_t ch) { (void)ch; return false; }

    virtual bool on_focus() { return false; }
    virtual bool on_blur() { return false; }

    // Focus system extensions
    virtual bool wants_arrow_navigation() const { return false; }  // Override true if widget handles arrows (TextInput)
    virtual bool on_escape() { return false; }                     // Handle Escape key (blur, clear selection, etc.)
    virtual Widget* get_preferred_initial_focus() { return nullptr; }  // For dialogs: which child to focus

    virtual void on_viewport_changed(float vp_top, float vp_bottom) { (void)vp_top; (void)vp_bottom; }

    // Animation tick - called every frame for smooth animations
    virtual void tick(float dt) {
        bool needs_redraw = false;
        if (hover_anim && hover_anim->update(dt, Theme::HOVER_TRANSITION_MS)) {
            needs_redraw = true;
        }
        if (press_anim && press_anim->update(dt)) {
            needs_redraw = true;
        }
        if (needs_redraw) {
            set_dirty();
        }
    }

    // Get eased hover value (0.0 to 1.0) for rendering
    float get_hover_t() const {
        return hover_anim ? hover_anim->eased() : 0.0f;
    }

    // Get current press scale (1.0 = normal, 0.98 = pressed)
    float get_press_scale() const {
        return press_anim ? press_anim->scale : 1.0f;
    }

    bool is_visible() const { return (flags & WidgetFlags::Visible) != 0; }
    bool is_enabled() const { return (flags & WidgetFlags::Enabled) != 0; }
    bool is_focused() const { return (flags & WidgetFlags::Focused) != 0; }
    bool is_hovered() const { return (flags & WidgetFlags::Hovered) != 0; }
    bool is_pressed() const { return (flags & WidgetFlags::Pressed) != 0; }

    void set_dirty() {
        flags |= WidgetFlags::Dirty;
        if (g_animation_scheduler.hwnd) {
            InvalidateRect(g_animation_scheduler.hwnd, nullptr, FALSE);
        }
    }

    void set_layout_dirty() {
        flags |= WidgetFlags::LayoutDirty;
        set_dirty();
    }

    bool hit_test(float x, float y) const {
        return is_visible() && is_enabled() && rect.contains(x, y);
    }
};

// ============================================================================
// Tree Manipulation Functions
// ============================================================================

static void widget_add_child(Widget* parent, Widget* child) {
    if (!parent || !child) return;

    if (child->parent) {
        if (child->prev_sibling) {
            child->prev_sibling->next_sibling = child->next_sibling;
        } else if (child->parent->first_child == child) {
            child->parent->first_child = child->next_sibling;
        }
        if (child->next_sibling) {
            child->next_sibling->prev_sibling = child->prev_sibling;
        } else {
            child->parent->last_child = child->prev_sibling;
        }
        child->parent->child_count--;
    }

    child->parent = parent;
    child->next_sibling = nullptr;
    child->prev_sibling = parent->last_child;

    if (parent->last_child) {
        parent->last_child->next_sibling = child;
    } else {
        parent->first_child = child;
    }
    parent->last_child = child;
    parent->child_count++;
}

static void widget_remove_child(Widget* parent, Widget* child) {
    if (!parent || !child || child->parent != parent) return;

    if (child->prev_sibling) {
        child->prev_sibling->next_sibling = child->next_sibling;
    } else {
        parent->first_child = child->next_sibling;
    }

    if (child->next_sibling) {
        child->next_sibling->prev_sibling = child->prev_sibling;
    } else {
        parent->last_child = child->prev_sibling;
    }

    child->parent = nullptr;
    child->prev_sibling = nullptr;
    child->next_sibling = nullptr;
    parent->child_count--;
}

// ============================================================================
// Widget Arena Allocator
// ============================================================================

struct WidgetArena {
    static constexpr size_t BLOCK_SIZE = 64 * 1024;
    static constexpr size_t DTOR_CHUNK = 256;

    struct Block {
        uint8_t data[BLOCK_SIZE];
        size_t used = 0;
        Block* next = nullptr;
    };

    // Dedicated heap allocation for requests that don't fit in a fixed
    // Block. Without this, alloc() would silently return a pointer to a
    // 64 KB Block for a larger request, and the caller's constructor/
    // memset would overflow past the block end into adjacent heap.
    struct OversizeBlock {
        OversizeBlock* next;
        // payload follows; aligned past the header
    };

    // Destructor list: non-trivially-destructible objects allocated from
    // the arena register here so reset()/destroy() can clean them up.
    // Without this, arena resets leak COM refs, heap allocs, and (most
    // importantly) AnimationScheduler active_count for live animations.
    struct DtorEntry {
        void* obj;
        void (*fn)(void*);
    };

    Block* first_block = nullptr;
    Block* current_block = nullptr;
    OversizeBlock* oversize_head = nullptr;

    DtorEntry* dtors = nullptr;
    size_t dtor_count = 0;
    size_t dtor_capacity = 0;

    void* alloc(size_t size, size_t alignment = 8) {
        // Oversized requests get a dedicated heap allocation. Forcing them
        // through the fixed-Block path returns a pointer with too little
        // backing memory, so the next memset/ctor in the caller walks past
        // the block end. The header sits before the payload and is linked
        // into oversize_head so reset()/destroy() can free it.
        if (size > BLOCK_SIZE) {
            size_t header = sizeof(OversizeBlock);
            // HeapAlloc is 8/16-byte aligned; pad only for stronger alignment.
            size_t align_pad = (alignment > 8) ? (alignment - 8) : 0;
            void* raw = HeapAlloc(GetProcessHeap(), HEAP_ZERO_MEMORY, header + align_pad + size);
            if (!raw) return nullptr;
            OversizeBlock* ob = static_cast<OversizeBlock*>(raw);
            ob->next = oversize_head;
            oversize_head = ob;
            uintptr_t payload = reinterpret_cast<uintptr_t>(ob) + header;
            payload = (payload + alignment - 1) & ~(alignment - 1);
            return reinterpret_cast<void*>(payload);
        }

        if (!current_block) {
            first_block = static_cast<Block*>(HeapAlloc(GetProcessHeap(), HEAP_ZERO_MEMORY, sizeof(Block)));
            if (!first_block) return nullptr;
            current_block = first_block;
        }

        size_t aligned_used = (current_block->used + alignment - 1) & ~(alignment - 1);

        if (aligned_used + size > BLOCK_SIZE) {
            // HEAP_ZERO_MEMORY is REQUIRED — Block has in-class initializers
            // (used=0, next=nullptr) but HeapAlloc doesn't run constructors,
            // so without zeroing the chain pointer is garbage and destroy()
            // walks off into invalid memory.
            Block* new_block = static_cast<Block*>(HeapAlloc(GetProcessHeap(), HEAP_ZERO_MEMORY, sizeof(Block)));
            if (!new_block) return nullptr;
            current_block->next = new_block;
            current_block = new_block;
            aligned_used = 0;
        }

        void* result = current_block->data + aligned_used;
        current_block->used = aligned_used + size;
        return result;
    }

    bool register_dtor(void* obj, void (*fn)(void*)) {
        if (dtor_count == dtor_capacity) {
            size_t new_cap = dtor_capacity ? dtor_capacity * 2 : DTOR_CHUNK;
            DtorEntry* new_list = static_cast<DtorEntry*>(
                HeapAlloc(GetProcessHeap(), 0, new_cap * sizeof(DtorEntry)));
            if (!new_list) return false;
            if (dtors) {
                memcpy(new_list, dtors, dtor_count * sizeof(DtorEntry));
                HeapFree(GetProcessHeap(), 0, dtors);
            }
            dtors = new_list;
            dtor_capacity = new_cap;
        }
        dtors[dtor_count++] = { obj, fn };
        return true;
    }

    template<typename T, typename... Args>
    T* create(Args&&... args) {
        void* mem = alloc(sizeof(T), alignof(T));
        if (!mem) return nullptr;
        T* obj = new (mem) T(static_cast<Args&&>(args)...);
        if constexpr (!std::is_trivially_destructible<T>::value) {
            register_dtor(obj, [](void* p) { static_cast<T*>(p)->~T(); });
        }
        return obj;
    }

    void run_destructors() {
        // Run in reverse allocation order so children destruct before parents.
        for (size_t i = dtor_count; i-- > 0; ) {
            dtors[i].fn(dtors[i].obj);
        }
        dtor_count = 0;
    }

    void free_oversize_blocks() {
        OversizeBlock* ob = oversize_head;
        while (ob) {
            OversizeBlock* next = ob->next;
            HeapFree(GetProcessHeap(), 0, ob);
            ob = next;
        }
        oversize_head = nullptr;
    }

    void reset() {
        run_destructors();
        // Oversize blocks are per-allocation; freeing them on reset matches
        // the lifetime of the objects they backed (just destructed above).
        free_oversize_blocks();
        Block* block = first_block;
        while (block) {
            block->used = 0;
            block = block->next;
        }
        current_block = first_block;
    }

    void destroy() {
        run_destructors();
        free_oversize_blocks();
        if (dtors) {
            HeapFree(GetProcessHeap(), 0, dtors);
            dtors = nullptr;
            dtor_capacity = 0;
        }
        Block* block = first_block;
        while (block) {
            Block* next = block->next;
            HeapFree(GetProcessHeap(), 0, block);
            block = next;
        }
        first_block = nullptr;
        current_block = nullptr;
    }

    ~WidgetArena() {
        destroy();
    }
};

WidgetArena g_widget_arena = {};

// ============================================================================
// Render Context
// ============================================================================

struct RenderContext {
    ID2D1RenderTarget* target = nullptr;
    ID2D1SolidColorBrush* brush = nullptr;

    D2D1_RECT_F clip_stack[16];
    size_t clip_depth = 0;

    void push_clip(const D2D1_RECT_F& rect) {
        if (clip_depth < 16 && target) {
            clip_stack[clip_depth++] = rect;
            target->PushAxisAlignedClip(rect, D2D1_ANTIALIAS_MODE_PER_PRIMITIVE);
        }
    }

    void pop_clip() {
        if (clip_depth > 0 && target) {
            clip_depth--;
            target->PopAxisAlignedClip();
        }
    }

    void fill_rect(const D2D1_RECT_F& rect, uint32_t color) {
        if (!target || !brush) return;
        brush->SetColor(color_from_argb(color));
        target->FillRectangle(rect, brush);
    }

    void fill_rounded_rect(const D2D1_RECT_F& rect, float radius, uint32_t color) {
        if (!target || !brush) return;
        brush->SetColor(color_from_argb(color));
        D2D1_ROUNDED_RECT rounded = { rect, radius, radius };
        target->FillRoundedRectangle(rounded, brush);
    }

    void draw_rect(const D2D1_RECT_F& rect, uint32_t color, float stroke = 1.0f) {
        if (!target || !brush) return;
        brush->SetColor(color_from_argb(color));
        target->DrawRectangle(rect, brush, stroke);
    }

    void draw_text(const wchar_t* text, size_t len, IDWriteTextFormat* format,
                   const D2D1_RECT_F& rect, uint32_t color) {
        if (!target || !brush || !text || !format) return;
        brush->SetColor(color_from_argb(color));
        target->DrawText(text, static_cast<UINT32>(len), format, rect, brush);
    }

    void draw_line(float x1, float y1, float x2, float y2, uint32_t color, float width = 1.0f) {
        if (!target || !brush) return;
        brush->SetColor(color_from_argb(color));
        target->DrawLine(D2D1::Point2F(x1, y1), D2D1::Point2F(x2, y2), brush, width);
    }

    // Draw soft shadow under a rounded rect (multi-layer approximation)
    void draw_shadow(const D2D1_RECT_F& rect, float radius, float offset_y, float blur, float opacity) {
        if (!target || !brush) return;

        const int LAYERS = 4;
        for (int i = LAYERS - 1; i >= 0; i--) {
            float expand = (blur / LAYERS) * (i + 1);
            float layer_alpha = (opacity / LAYERS) * (1.0f - (float)i / LAYERS);

            D2D1_RECT_F shadow_rect = D2D1::RectF(
                rect.left - expand,
                rect.top - expand + offset_y,
                rect.right + expand,
                rect.bottom + expand + offset_y
            );

            uint32_t shadow_color = (static_cast<uint8_t>(layer_alpha * 255) << 24);
            fill_rounded_rect(shadow_rect, radius + expand * 0.5f, shadow_color);
        }
    }

    // Draw dialog-style shadow
    void draw_dialog_shadow(const D2D1_RECT_F& rect, float radius) {
        draw_shadow(rect, radius,
                   Theme::SHADOW_DIALOG_OFFSET_Y,
                   Theme::SHADOW_DIALOG_BLUR,
                   Theme::SHADOW_DIALOG_OPACITY);
    }

    // Draw tooltip-style shadow
    void draw_tooltip_shadow(const D2D1_RECT_F& rect, float radius) {
        draw_shadow(rect, radius,
                   Theme::SHADOW_TOOLTIP_OFFSET_Y,
                   Theme::SHADOW_TOOLTIP_BLUR,
                   Theme::SHADOW_TOOLTIP_OPACITY);
    }

    // Draw focus ring with outer glow (for keyboard focus)
    void draw_focus_ring(const D2D1_RECT_F& rect, float radius) {
        if (!target || !brush) return;

        // Outer glow
        D2D1_RECT_F glow_rect = D2D1::RectF(
            rect.left - Theme::FOCUS_GLOW_SPREAD,
            rect.top - Theme::FOCUS_GLOW_SPREAD,
            rect.right + Theme::FOCUS_GLOW_SPREAD,
            rect.bottom + Theme::FOCUS_GLOW_SPREAD
        );
        brush->SetColor(color_from_argb(Theme::FOCUS_GLOW));
        D2D1_ROUNDED_RECT glow_rr = { glow_rect, radius + Theme::FOCUS_GLOW_SPREAD, radius + Theme::FOCUS_GLOW_SPREAD };
        target->FillRoundedRectangle(glow_rr, brush);

        // Inner ring
        D2D1_RECT_F ring_rect = D2D1::RectF(
            rect.left - Theme::FOCUS_RING_OFFSET,
            rect.top - Theme::FOCUS_RING_OFFSET,
            rect.right + Theme::FOCUS_RING_OFFSET,
            rect.bottom + Theme::FOCUS_RING_OFFSET
        );
        brush->SetColor(color_from_argb(Theme::ACCENT));
        D2D1_ROUNDED_RECT ring_rr = { ring_rect, radius + Theme::FOCUS_RING_OFFSET, radius + Theme::FOCUS_RING_OFFSET };
        target->DrawRoundedRectangle(ring_rr, brush, Theme::FOCUS_RING_WIDTH);
    }
};

// ============================================================================
// Widget Tree
// ============================================================================

struct WidgetTree {
    Widget* root = nullptr;
    RenderContext ctx;

    void render(ID2D1HwndRenderTarget* target) {
        if (!target || !root) return;

        ctx.target = target;

        if (!ctx.brush) {
            target->CreateSolidColorBrush(D2D1::ColorF(1.0f, 1.0f, 1.0f, 1.0f), &ctx.brush);
        }

        render_widget(root);
        clear_dirty_flags(root);
    }

    // Tick all widgets for animation updates
    void tick(float dt) {
        if (root) {
            tick_widget(root, dt);
        }
    }

private:
    void tick_widget(Widget* widget, float dt) {
        if (!widget || !widget->is_visible()) return;

        widget->tick(dt);

        Widget* child = widget->first_child;
        while (child) {
            tick_widget(child, dt);
            child = child->next_sibling;
        }
    }
    void render_widget(Widget* widget) {
        if (!widget || !widget->is_visible()) return;

        bool should_clip = (widget->flags & WidgetFlags::ClipChildren) != 0;
        if (should_clip) {
            D2D1_RECT_F clip_rect = D2D1::RectF(
                widget->rect.x, widget->rect.y,
                widget->rect.x + widget->rect.width,
                widget->rect.y + widget->rect.height
            );
            ctx.push_clip(clip_rect);
        }

        widget->render(ctx);

        if (!(widget->flags & WidgetFlags::RendersOwnChildren)) {
            Widget* child = widget->first_child;
            while (child) {
                render_widget(child);
                child = child->next_sibling;
            }
        }

        if (should_clip) {
            ctx.pop_clip();
        }
    }

    void clear_dirty_flags(Widget* widget) {
        if (!widget) return;
        widget->flags &= ~(WidgetFlags::Dirty | WidgetFlags::LayoutDirty);
        Widget* child = widget->first_child;
        while (child) {
            clear_dirty_flags(child);
            child = child->next_sibling;
        }
    }
};

// ============================================================================
// Focus Memory (for save/restore focus across dialog open/close)
// ============================================================================

struct FocusMemory {
    // Stack of saved focus per nested scope (dialog inside dialog, etc.).
    // 16 is generous — even a dialog-on-dialog-on-dialog flow is at most 3.
    static constexpr size_t MAX_DEPTH = 16;

    struct Entry {
        WidgetId widget_id;   // Widget that had focus (0 if none)
        WidgetId scope_id;    // The scope (dialog/panel) this belongs to
    };

    Entry stack[MAX_DEPTH] = {};
    size_t depth = 0;

    void push(WidgetId widget, WidgetId scope) {
        if (depth < MAX_DEPTH) {
            stack[depth].widget_id = widget;
            stack[depth].scope_id = scope;
            depth++;
        }
    }

    WidgetId pop(WidgetId scope) {
        // Pop entries until we find one matching the scope. Previously the loop
        // body unconditionally returned, so any non-matching top entry (from a
        // dialog closed out of LIFO order) would prevent restoring the saved
        // focus underneath. Now skip non-matching tops, then return.
        while (depth > 0 && stack[depth - 1].scope_id != scope) {
            depth--;
        }
        if (depth > 0) {
            depth--;
            return stack[depth].widget_id;
        }
        return 0;
    }

    void clear() {
        depth = 0;
    }
};

// ============================================================================
// Event Dispatcher
// ============================================================================

struct EventDispatcher {
    Widget* root = nullptr;
    Widget* focused = nullptr;
    Widget* hovered = nullptr;
    Widget* captured = nullptr;

    // Focus memory for save/restore across scope changes
    FocusMemory focus_memory;

    Widget* hit_test(Widget* widget, float x, float y) {
        if (!widget || !(widget->flags & WidgetFlags::Visible)) return nullptr;
        if (!(widget->flags & WidgetFlags::Enabled)) return nullptr;
        if (!widget->rect.contains(x, y)) return nullptr;

        // Walk children back-to-front (later siblings render on top, so they
        // must hit-test first). The Widget struct maintains last_child, so
        // no need to scan the sibling list to find the tail.
        for (Widget* child = widget->last_child; child; child = child->prev_sibling) {
            Widget* hit = hit_test(child, x, y);
            if (hit) return hit;
        }
        return widget;
    }

    bool is_blocking() const { return root != nullptr; }

    bool dispatch_mouse_move(float x, float y) {
        if (!root) return false;

        Widget* target = captured ? captured : hit_test(root, x, y);

        if (target != hovered) {
            if (hovered) {
                hovered->flags &= ~WidgetFlags::Hovered;
                hovered->on_mouse_leave();
                hovered->set_dirty();
            }
            if (target) {
                target->flags |= WidgetFlags::Hovered;
                target->on_mouse_enter();
                target->set_dirty();
            }
            hovered = target;
        }

        if (target && (target->flags & WidgetFlags::Enabled)) {
            if (captured) {
                target->on_mouse_move(x, y);
            } else {
                target->on_mouse_move(x - target->rect.x, y - target->rect.y);
            }
        }

        return true;
    }

    bool dispatch_mouse_down(float x, float y, int button) {
        if (!root) return false;

        // Mouse click clears keyboard focus indicator from any focused widget
        if (focused) {
            focused->flags &= ~WidgetFlags::KeyboardFocused;
            focused->set_dirty();
        }

        Widget* target = hit_test(root, x, y);

        if (target && (target->flags & WidgetFlags::Focusable)) {
            set_focus(target, false);  // mouse click = no keyboard focus ring
        } else {
            set_focus(nullptr);
        }

        if (target && (target->flags & WidgetFlags::Enabled)) {
            target->flags |= WidgetFlags::Pressed;
            if (target->flags & WidgetFlags::CapturesMouse) {
                captured = target;
            }
            target->on_mouse_down(x - target->rect.x, y - target->rect.y, button);
            target->set_dirty();
        }

        return true;
    }

    bool dispatch_mouse_up(float x, float y, int button) {
        if (!root) return false;

        Widget* target = captured ? captured : hit_test(root, x, y);

        if (target && (target->flags & WidgetFlags::Enabled)) {
            target->flags &= ~WidgetFlags::Pressed;
            // Coordinate convention (matches dispatch_mouse_move):
            //   captured  → absolute coordinates (mouse may be outside widget rect)
            //   uncaptured → coordinates relative to widget's rect
            if (captured) {
                target->on_mouse_up(x, y, button);
            } else {
                target->on_mouse_up(x - target->rect.x, y - target->rect.y, button);
            }
            target->set_dirty();
        }

        captured = nullptr;
        return true;
    }

    bool dispatch_mouse_wheel(float x, float y, float delta) {
        if (!root) return false;

        Widget* target = hit_test(root, x, y);

        while (target) {
            float rel_x = x - target->rect.x;
            float rel_y = y - target->rect.y;
            if (target->on_mouse_wheel(rel_x, rel_y, delta)) {
                target->set_dirty();
                return true;
            }
            target = target->parent;
        }

        return false;
    }

    bool dispatch_mouse_hwheel(float x, float y, float delta) {
        if (!root) return false;

        Widget* target = hit_test(root, x, y);

        while (target) {
            float rel_x = x - target->rect.x;
            float rel_y = y - target->rect.y;
            if (target->on_mouse_hwheel(rel_x, rel_y, delta)) {
                target->set_dirty();
                return true;
            }
            target = target->parent;
        }

        return false;
    }

    bool dispatch_double_click(float x, float y, int button) {
        if (!root) return false;

        Widget* target = hit_test(root, x, y);
        if (!target) return false;

        float rel_x = x - target->rect.x;
        float rel_y = y - target->rect.y;

        if (target->on_double_click(rel_x, rel_y, button)) {
            target->set_dirty();
            return true;
        }

        return false;
    }

    bool dispatch_key_down(int vk, bool ctrl, bool shift, bool alt) {
        if (!root) return false;

        // Tab navigation
        if (vk == VK_TAB && !ctrl && !alt) {
            tab_navigate(shift);
            return true;
        }

        // Escape handling (multi-level)
        if (vk == VK_ESCAPE && !ctrl && !shift && !alt) {
            if (dispatch_escape()) {
                return true;
            }
        }

        // Arrow key navigation within focus groups
        if ((vk == VK_LEFT || vk == VK_RIGHT || vk == VK_UP || vk == VK_DOWN) && !ctrl && !alt) {
            if (arrow_navigate(vk)) {
                return true;
            }
            // If arrow_navigate returns false, fall through to widget handling
        }

        // Only dispatch to focused widget, not the entire tree
        // If nothing is focused, don't consume the key
        if (!focused) {
            return false;
        }

        Widget* target = focused;
        while (target) {
            if (target->on_key_down(vk, ctrl, shift, alt)) {
                target->set_dirty();
                return true;  // Widget handled the key
            }
            target = target->parent;
        }

        return false;  // No widget handled the key
    }

    bool dispatch_key_up(int vk) {
        if (!root || !focused) return false;
        if (focused->on_key_up(vk)) {
            focused->set_dirty();
            return true;
        }
        return false;
    }

    bool dispatch_char(wchar_t ch) {
        if (!root || !focused) return false;
        if (focused->on_char(ch)) {
            focused->set_dirty();
            return true;
        }
        return false;
    }

    void set_focus(Widget* widget, bool keyboard = false) {
        if (widget && (!(widget->flags & WidgetFlags::Visible) ||
                       !(widget->flags & WidgetFlags::Enabled) ||
                       !(widget->flags & WidgetFlags::Focusable))) {
            widget = nullptr;
        }

        // Clear KeyboardFocused from old widget regardless
        if (focused && focused != widget) {
            focused->flags &= ~(WidgetFlags::Focused | WidgetFlags::KeyboardFocused);
            focused->on_blur();
            focused->set_dirty();
        }

        // If same widget, just update keyboard state
        if (widget == focused) {
            if (keyboard && widget) {
                widget->flags |= WidgetFlags::KeyboardFocused;
                widget->set_dirty();
            }
            return;
        }

        focused = widget;

        if (focused) {
            focused->flags |= WidgetFlags::Focused;
            if (keyboard) {
                focused->flags |= WidgetFlags::KeyboardFocused;
            }
            focused->on_focus();
            focused->set_dirty();
        }
    }

    void clear_hover() {
        if (hovered) {
            Widget* w = hovered;
            hovered = nullptr;
            w->flags &= ~WidgetFlags::Hovered;
            w->on_mouse_leave();
            w->set_dirty();
        }
    }

    void collect_focusable(Widget* widget, Widget** out, size_t* count, size_t max_count) {
        if (!widget || *count >= max_count) return;
        if (!(widget->flags & WidgetFlags::Visible)) return;
        if (!(widget->flags & WidgetFlags::Enabled)) return;

        if (widget->flags & WidgetFlags::Focusable) {
            out[*count] = widget;
            (*count)++;
        }

        for (Widget* child = widget->first_child; child; child = child->next_sibling) {
            collect_focusable(child, out, count, max_count);
        }
    }

    // Collect focusable widgets, respecting SkipTabStop flag
    void collect_focusable_for_tab(Widget* widget, Widget** out, size_t* count, size_t max_count, size_t* tree_order) {
        if (!widget || *count >= max_count) return;
        if (!(widget->flags & WidgetFlags::Visible)) return;
        if (!(widget->flags & WidgetFlags::Enabled)) return;

        // Check if focusable and not skipped for Tab
        if ((widget->flags & WidgetFlags::Focusable) && !(widget->flags & WidgetFlags::SkipTabStop)) {
            out[*count] = widget;
            (*count)++;
        }

        for (Widget* child = widget->first_child; child; child = child->next_sibling) {
            collect_focusable_for_tab(child, out, count, max_count, tree_order);
        }
    }

    // Sort focusable widgets by tab_index (stable sort preserving tree order for equal indices)
    // Uses insertion sort since we have a small fixed-size array
    void sort_by_tab_index(Widget** widgets, size_t count) {
        for (size_t i = 1; i < count; i++) {
            Widget* key = widgets[i];
            int16_t key_idx = key->tab_index;
            size_t j = i;

            // Move elements with higher tab_index to the right
            // tab_index 0 = tree order (default), positive = explicit order
            // For equal indices, preserve original (tree) order (stable sort)
            while (j > 0 && widgets[j - 1]->tab_index > key_idx) {
                widgets[j] = widgets[j - 1];
                j--;
            }
            widgets[j] = key;
        }
    }

    bool tab_navigate(bool shift) {
        if (!root) return false;

        // Tab order — generous cap so complex dialogs (file checklist with
        // many rows, large branch trees) don't silently lose tab stops.
        constexpr size_t MAX_FOCUSABLE = 512;
        Widget* focusable[MAX_FOCUSABLE];
        size_t count = 0;
        size_t tree_order = 0;
        collect_focusable_for_tab(root, focusable, &count, MAX_FOCUSABLE, &tree_order);

        if (count == 0) return false;

        // Sort by tab_index (widgets with tab_index > 0 come first, sorted by index)
        // Widgets with tab_index = 0 maintain tree order
        sort_by_tab_index(focusable, count);

        size_t current_idx = count;
        for (size_t i = 0; i < count; i++) {
            if (focusable[i] == focused) {
                current_idx = i;
                break;
            }
        }

        size_t next_idx;
        if (current_idx >= count) {
            next_idx = shift ? (count - 1) : 0;
        } else if (shift) {
            next_idx = (current_idx == 0) ? (count - 1) : (current_idx - 1);
        } else {
            next_idx = (current_idx + 1) % count;
        }

        set_focus(focusable[next_idx], true);  // keyboard = true for Tab navigation
        return true;
    }

    // -------------------------------------------------------------------------
    // Focus Group Navigation (Arrow Keys)
    // -------------------------------------------------------------------------

    // Find nearest ancestor with FocusGroup flag
    Widget* find_focus_group(Widget* from) {
        Widget* w = from ? from->parent : nullptr;
        while (w) {
            if (w->flags & WidgetFlags::FocusGroup) return w;
            w = w->parent;
        }
        return nullptr;
    }

    // Check if nav_direction allows navigation with this key
    bool direction_allows_key(NavDirection dir, int vk) {
        switch (dir) {
            case NavDirection::Auto:
                // Auto: allow all for now (can infer from parent later)
                return true;
            case NavDirection::Horizontal:
                return vk == VK_LEFT || vk == VK_RIGHT;
            case NavDirection::Vertical:
                return vk == VK_UP || vk == VK_DOWN;
            case NavDirection::Grid:
                return true;  // All arrows allowed
        }
        return false;
    }

    // Collect focusable children of a focus group (direct focusable descendants)
    void collect_group_focusables(Widget* group, Widget** out, size_t* count, size_t max_count) {
        if (!group || *count >= max_count) return;

        for (Widget* child = group->first_child; child; child = child->next_sibling) {
            if (!(child->flags & WidgetFlags::Visible)) continue;
            if (!(child->flags & WidgetFlags::Enabled)) continue;

            if (child->flags & WidgetFlags::Focusable) {
                out[*count] = child;
                (*count)++;
                if (*count >= max_count) return;
            }

            // Don't recurse into nested focus groups
            if (!(child->flags & WidgetFlags::FocusGroup)) {
                collect_group_focusables(child, out, count, max_count);
            }
        }
    }

    // Navigate within a focus group using arrow keys
    bool arrow_navigate(int vk) {
        if (!focused) return false;

        // If focused widget handles arrow keys internally, don't navigate
        if (focused->wants_arrow_navigation()) return false;

        // Find the focus group containing the focused widget
        Widget* group = find_focus_group(focused);
        if (!group) return false;  // No focus group, don't handle

        // Check if the group's nav direction allows this key
        if (!direction_allows_key(group->nav_direction, vk)) return false;

        // Collect focusable widgets within the group
        constexpr size_t MAX_GROUP_FOCUSABLE = 256;
        Widget* group_focusables[MAX_GROUP_FOCUSABLE];
        size_t count = 0;
        collect_group_focusables(group, group_focusables, &count, MAX_GROUP_FOCUSABLE);

        if (count == 0) return false;

        // Find current focused widget's index
        size_t current_idx = count;
        for (size_t i = 0; i < count; i++) {
            if (group_focusables[i] == focused) {
                current_idx = i;
                break;
            }
        }

        if (current_idx >= count) return false;  // Focused widget not in group

        // Calculate next index based on arrow direction
        size_t next_idx = current_idx;
        bool forward = (vk == VK_RIGHT || vk == VK_DOWN);

        if (forward) {
            if (current_idx + 1 < count) {
                next_idx = current_idx + 1;
            }
            // At end: don't wrap, stay on current
        } else {
            if (current_idx > 0) {
                next_idx = current_idx - 1;
            }
            // At start: don't wrap, stay on current
        }

        if (next_idx != current_idx) {
            set_focus(group_focusables[next_idx], true);  // keyboard = true for arrow nav
        }

        return true;  // Consumed even if no movement (we're in a group)
    }

    // -------------------------------------------------------------------------
    // Escape Key Handling
    // -------------------------------------------------------------------------

    // Multi-level escape: widget -> focus group -> clear focus
    bool dispatch_escape() {
        if (!focused) return false;

        // Level 1: Let the focused widget handle escape first (e.g., clear selection)
        if (focused->on_escape()) {
            focused->set_dirty();
            return true;
        }

        // Level 2: If in a focus group, exit to the group itself (if focusable)
        Widget* group = find_focus_group(focused);
        if (group && (group->flags & WidgetFlags::Focusable)) {
            set_focus(group);
            return true;
        }

        // Level 3: Clear focus entirely
        set_focus(nullptr);
        return true;
    }

    // -------------------------------------------------------------------------
    // Focus Scope Management (for dialogs)
    // -------------------------------------------------------------------------

    // Find widget by ID in tree
    Widget* find_widget_by_id(Widget* tree, WidgetId id) {
        if (!tree) return nullptr;
        if (tree->id == id) return tree;

        for (Widget* child = tree->first_child; child; child = child->next_sibling) {
            Widget* found = find_widget_by_id(child, id);
            if (found) return found;
        }
        return nullptr;
    }

    // Find first focusable widget in a scope
    Widget* find_initial_focus(Widget* scope) {
        if (!scope) return nullptr;

        // First, check if scope has a get_preferred_initial_focus() override
        Widget* preferred = scope->get_preferred_initial_focus();
        if (preferred && (preferred->flags & WidgetFlags::Visible) &&
            (preferred->flags & WidgetFlags::Enabled) &&
            (preferred->flags & WidgetFlags::Focusable)) {
            return preferred;
        }

        // Next, look for widget with PreferInitialFocus flag
        constexpr size_t MAX_SEARCH = 256;
        Widget* focusable[MAX_SEARCH];
        size_t count = 0;
        collect_focusable(scope, focusable, &count, MAX_SEARCH);

        for (size_t i = 0; i < count; i++) {
            if (focusable[i]->flags & WidgetFlags::PreferInitialFocus) {
                return focusable[i];
            }
        }

        // Fall back to first focusable widget
        return count > 0 ? focusable[0] : nullptr;
    }

    // Save current focus and enter a new scope (e.g., opening a dialog)
    void push_focus_scope(Widget* scope) {
        if (!scope) return;

        // Save current focus to memory
        WidgetId current_focus_id = focused ? focused->id : 0;
        focus_memory.push(current_focus_id, scope->id);

        // Apply initial focus in the new scope
        Widget* initial = find_initial_focus(scope);
        set_focus(initial);
    }

    // Restore focus when leaving a scope (e.g., closing a dialog)
    void pop_focus_scope(Widget* scope) {
        if (!scope) return;

        // Retrieve saved focus
        WidgetId saved_id = focus_memory.pop(scope->id);

        // Restore focus if the widget still exists
        Widget* saved_widget = saved_id ? find_widget_by_id(root, saved_id) : nullptr;
        if (saved_widget && (saved_widget->flags & WidgetFlags::Visible) &&
            (saved_widget->flags & WidgetFlags::Enabled) &&
            (saved_widget->flags & WidgetFlags::Focusable)) {
            set_focus(saved_widget);
        } else {
            set_focus(nullptr);
        }
    }

    // Apply initial focus to the current root (useful when first showing a dialog)
    void apply_initial_focus() {
        Widget* initial = find_initial_focus(root);
        set_focus(initial);
    }
};

EventDispatcher g_event_dispatcher = {};
static EventDispatcher g_sidebar_dispatcher = {};
static EventDispatcher g_main_content_dispatcher = {};

// ============================================================================
// Layout Engine
// ============================================================================

namespace LayoutEngine {
    static void measure_tree(Widget* root, const LayoutConstraints& constraints) {
        if (!root || !(root->flags & WidgetFlags::Visible)) return;

        for (Widget* child = root->first_child; child; child = child->next_sibling) {
            if (child->flags & WidgetFlags::Visible) {
                measure_tree(child, constraints);
            }
        }

        root->measure(constraints);
    }

    static void layout_tree(Widget* root) {
        if (!root || !(root->flags & WidgetFlags::Visible)) return;

        root->layout();

        for (Widget* child = root->first_child; child; child = child->next_sibling) {
            if (child->flags & WidgetFlags::Visible) {
                layout_tree(child);
            }
        }
    }
}

// ============================================================================
// Flex Container
// ============================================================================

enum class FlexDirection : uint8_t { Row, Column };
enum class FlexAlign : uint8_t { Start, Center, End, Stretch };
enum class FlexJustify : uint8_t { Start, Center, End, SpaceBetween, SpaceAround };

struct FlexContainer : Widget {
    FlexDirection direction = FlexDirection::Column;
    FlexAlign align = FlexAlign::Start;
    FlexJustify justify = FlexJustify::Start;
    float gap = 0.0f;

    FlexContainer() {
        flags |= WidgetFlags::RendersOwnChildren;
    }

    void measure(const LayoutConstraints& constraints) override {
        float main_size = 0.0f;
        float cross_size = 0.0f;
        size_t visible_count = 0;

        bool is_row = (direction == FlexDirection::Row);

        LayoutConstraints child_constraints;
        child_constraints.min_width = 0.0f;
        child_constraints.max_width = is_row ? 100000.0f : constraints.max_width;
        child_constraints.min_height = 0.0f;
        child_constraints.max_height = is_row ? constraints.max_height : 100000.0f;

        for (Widget* child = first_child; child; child = child->next_sibling) {
            if (!(child->flags & WidgetFlags::Visible)) continue;
            visible_count++;

            child->measure(child_constraints);

            if (child->flex <= 0.0f) {
                if (is_row) {
                    main_size += child->preferred_width;
                    cross_size = fmaxf(cross_size, child->preferred_height);
                } else {
                    main_size += child->preferred_height;
                    cross_size = fmaxf(cross_size, child->preferred_width);
                }
            }
        }

        if (visible_count > 1) {
            main_size += gap * (visible_count - 1);
        }

        if (is_row) {
            preferred_width = main_size + padding_left + padding_right;
            preferred_height = cross_size + padding_top + padding_bottom;
        } else {
            preferred_width = cross_size + padding_left + padding_right;
            preferred_height = main_size + padding_top + padding_bottom;
        }

        preferred_width = fminf(fmaxf(preferred_width, constraints.min_width), constraints.max_width);
        preferred_height = fminf(fmaxf(preferred_height, constraints.min_height), constraints.max_height);

        rect.width = preferred_width;
        rect.height = preferred_height;
    }

    void layout() override {
        bool is_row = (direction == FlexDirection::Row);
        float content_start = is_row ? (rect.x + padding_left) : (rect.y + padding_top);
        float available = is_row ?
            (rect.width - padding_left - padding_right) :
            (rect.height - padding_top - padding_bottom);

        float used = 0.0f;
        float total_flex = 0.0f;
        size_t visible_count = 0;

        for (Widget* child = first_child; child; child = child->next_sibling) {
            if (!(child->flags & WidgetFlags::Visible)) continue;
            visible_count++;

            if (child->flex > 0.0f) {
                total_flex += child->flex;
            } else {
                used += is_row ? child->preferred_width : child->preferred_height;
            }
        }

        if (visible_count > 1) {
            used += gap * (visible_count - 1);
        }

        float flex_space = fmaxf(0.0f, available - used);

        float total_content_size = used;
        if (total_flex > 0.0f) {
            total_content_size += flex_space;
        }

        float pos = content_start;
        switch (justify) {
            case FlexJustify::End:
                pos = content_start + available - total_content_size;
                break;
            case FlexJustify::Center:
                pos = content_start + (available - total_content_size) / 2.0f;
                break;
            case FlexJustify::SpaceBetween:
                break;
            case FlexJustify::SpaceAround:
                if (visible_count > 0) {
                    float space_per_item = (available - used) / visible_count;
                    pos = content_start + space_per_item / 2.0f;
                }
                break;
            default:
                break;
        }

        float cross_start = is_row ? (rect.y + padding_top) : (rect.x + padding_left);
        float cross_size = is_row ?
            (rect.height - padding_top - padding_bottom) :
            (rect.width - padding_left - padding_right);

        float item_gap = gap;
        if (total_flex <= 0.0f) {
            if (justify == FlexJustify::SpaceBetween && visible_count > 1) {
                item_gap = (available - used + gap * (visible_count - 1)) / (visible_count - 1);
            } else if (justify == FlexJustify::SpaceAround && visible_count > 0) {
                item_gap = (available - used) / visible_count;
            }
        }

        for (Widget* child = first_child; child; child = child->next_sibling) {
            if (!(child->flags & WidgetFlags::Visible)) continue;

            float child_main = is_row ? child->preferred_width : child->preferred_height;
            if (child->flex > 0.0f && total_flex > 0.0f) {
                child_main = (child->flex / total_flex) * flex_space;
            }

            if (is_row) {
                child->rect.x = pos;
                child->rect.width = child_main;
            } else {
                child->rect.y = pos;
                child->rect.height = child_main;
            }

            float child_cross = is_row ? child->preferred_height : child->preferred_width;
            float cross_pos = cross_start;

            switch (align) {
                case FlexAlign::Center:
                    cross_pos = cross_start + (cross_size - child_cross) / 2.0f;
                    break;
                case FlexAlign::End:
                    cross_pos = cross_start + cross_size - child_cross;
                    break;
                case FlexAlign::Stretch:
                    child_cross = cross_size;
                    break;
                default:
                    break;
            }

            if (is_row) {
                child->rect.y = cross_pos;
                child->rect.height = child_cross;
            } else {
                child->rect.x = cross_pos;
                child->rect.width = child_cross;
            }

            pos += child_main + item_gap;
            child->layout();
        }
    }

    void render(RenderContext& ctx) override {
        for (Widget* child = first_child; child; child = child->next_sibling) {
            if (child->flags & WidgetFlags::Visible) {
                child->render(ctx);
            }
        }
    }

    bool on_mouse_down(float x, float y, int button) override {
        float abs_x = rect.x + x;
        float abs_y = rect.y + y;

        for (Widget* child = first_child; child; child = child->next_sibling) {
            if (!(child->flags & WidgetFlags::Visible)) continue;
            if (child->hit_test(abs_x, abs_y)) {
                float child_x = abs_x - child->rect.x;
                float child_y = abs_y - child->rect.y;
                if (child->on_mouse_down(child_x, child_y, button)) {
                    return true;
                }
            }
        }
        return false;
    }

    bool on_mouse_up(float x, float y, int button) override {
        float abs_x = rect.x + x;
        float abs_y = rect.y + y;

        for (Widget* child = first_child; child; child = child->next_sibling) {
            if (!(child->flags & WidgetFlags::Visible)) continue;
            if (child->hit_test(abs_x, abs_y)) {
                float child_x = abs_x - child->rect.x;
                float child_y = abs_y - child->rect.y;
                if (child->on_mouse_up(child_x, child_y, button)) {
                    return true;
                }
            }
        }
        return false;
    }

    bool on_mouse_move(float x, float y) override {
        float abs_x = rect.x + x;
        float abs_y = rect.y + y;

        for (Widget* child = first_child; child; child = child->next_sibling) {
            if (!(child->flags & WidgetFlags::Visible)) continue;
            if (child->hit_test(abs_x, abs_y)) {
                float child_x = abs_x - child->rect.x;
                float child_y = abs_y - child->rect.y;
                if (child->on_mouse_move(child_x, child_y)) {
                    return true;
                }
            }
        }
        return false;
    }

    bool on_mouse_wheel(float x, float y, float delta) override {
        for (Widget* child = first_child; child; child = child->next_sibling) {
            if (!(child->flags & WidgetFlags::Visible)) continue;
            float child_x = x - (child->rect.x - rect.x);
            float child_y = y - (child->rect.y - rect.y);
            if (child->on_mouse_wheel(child_x, child_y, delta)) {
                return true;
            }
        }
        return false;
    }

    bool on_double_click(float x, float y, int button) override {
        float abs_x = rect.x + x;
        float abs_y = rect.y + y;

        for (Widget* child = first_child; child; child = child->next_sibling) {
            if (!(child->flags & WidgetFlags::Visible)) continue;
            if (child->hit_test(abs_x, abs_y)) {
                float child_x = abs_x - child->rect.x;
                float child_y = abs_y - child->rect.y;
                if (child->on_double_click(child_x, child_y, button)) {
                    return true;
                }
            }
        }
        return false;
    }
};

